workflow-item.script:
var req = new Properties();

req.put("vmName", vmName);
req.put("tagName", tagName);
req.put("tagDescription", tagDescription);
req.put("categoryName", categoryName);


requestObject = req;

System.log("Created requestObject");

function Handler($context, $inputs) {

    $vCenter = $inputs.vCenter
    $vcUser = $inputs.vcUser
    $vcPass = $inputs.vcPassword

    $tagName = $inputs.requestObject.tagName
    $description = $inputs.requestObject.tagDescription
    $categoryName = $inputs.requestObject.categoryName

    # FIX 1: Ignore untrusted SSL certificates before attempting connection
    Set-PowerCLIConfiguration -InvalidCertificateAction Ignore -Confirm:$false | Out-Null

    # FIX 2: Added -ErrorAction Stop so it crashes cleanly here if vCenter is unreachable
    Connect-VIServer `
        -Server $vCenter `
        -User $vcUser `
        -Password $vcPass `
        -ErrorAction Stop | Out-Null

    try {
        $tag = Get-Tag -Name $tagName -ErrorAction SilentlyContinue

        if (!$tag) {
            $tag = New-Tag `
                -Name $tagName `
                -Description $description `
                -Category $categoryName `
                -ErrorAction Stop

            # FIX 3: Use Add-Member to safely add properties to the vRO PSObject wrapper
            $inputs.requestObject | Add-Member -NotePropertyName "tagCreated" -NotePropertyValue $true -Force
        }
        else {
            # FIX 3: Use Add-Member here as well
            $inputs.requestObject | Add-Member -NotePropertyName "tagCreated" -NotePropertyValue $false -Force
        }

        return @{
            requestObject = $inputs.requestObject
        }
    }
    catch {
        # Escalates any execution errors up to the vRO Engine clearly
        throw $_
    }
    finally {
        # Only attempt disconnect if a connection was actually established
        Disconnect-VIServer -Server $vCenter -Confirm:$false -ErrorAction SilentlyContinue | Out-Null
    }
}

function Handler($context, $inputs) {

    # --- Inputs ---
    $vCenter = $inputs.vCenter
    $vcUser = $inputs.vcUser
    $vcPass = $inputs.vcPassword

    $vmName = $inputs.requestObject.vmName
    $tagName = $inputs.requestObject.tagName

    # --- Guard Clauses (Ensures bindings are set in vRO) ---
    if ([string]::IsNullOrEmpty($vCenter)) { throw "vRO Task Input Error: 'vCenter' binding is missing or empty." }
    if ([string]::IsNullOrEmpty($vcUser))  { throw "vRO Task Input Error: 'vcUser' binding is missing or empty." }
    if ([string]::IsNullOrEmpty($vcPass))  { throw "vRO Task Input Error: 'vcPassword' binding is missing or empty." }

    # --- PowerCLI Configuration ---
    Set-PowerCLIConfiguration -InvalidCertificateAction Ignore -Confirm:$false | Out-Null

    # --- Connection ---
    Connect-VIServer `
        -Server $vCenter `
        -User $vcUser `
        -Password $vcPass `
        -ErrorAction Stop | Out-Null

    try {
        $vm = Get-VM -Name $vmName -ErrorAction Stop
        $tag = Get-Tag -Name $tagName -ErrorAction Stop

        # Check if the tag is already assigned to the VM
        $existing = Get-TagAssignment -Entity $vm -ErrorAction SilentlyContinue |
            Where-Object {$_.Tag.Name -eq $tagName}

        if (!$existing) {
            New-TagAssignment `
                -Entity $vm `
                -Tag $tag `
                -ErrorAction Stop | Out-Null
        }

        # Return status and object back to vRO
        return @{
            status = "SUCCESS"
            requestObject = $inputs.requestObject
        }
    }
    catch {
        throw $_
    }
    finally {
        Disconnect-VIServer -Server $vCenter -Confirm:$false -ErrorAction SilentlyContinue | Out-Null
    }
}

function Handler($context, $inputs) {

    $vCenter = $inputs.vCenter
    $vcUser = $inputs.vcUser
    $vcPass = $inputs.vcPassword
    $categoryName = $inputs.requestObject.categoryName

    Set-PowerCLIConfiguration -InvalidCertificateAction Ignore -Confirm:$false | Out-Null

    Connect-VIServer `
        -Server $vCenter `
        -User $vcUser `
        -Password $vcPass -ErrorAction Stop | Out-Null

    try {
        $category = Get-TagCategory -Name $categoryName -ErrorAction SilentlyContinue

        if (!$category) {
            $category = New-TagCategory `
                -Name $categoryName `
                -Cardinality Multiple `
                -EntityType VirtualMachine `
                -ErrorAction Stop

            # FIX: Use Add-Member to dynamically add the property to the PSObject
            $inputs.requestObject | Add-Member -NotePropertyName "categoryCreated" -NotePropertyValue $true -Force
        }
        else {
            # FIX: Use Add-Member here as well
            $inputs.requestObject | Add-Member -NotePropertyName "categoryCreated" -NotePropertyValue $false -Force
        }

        # Return the modified object back to vRO
        return @{
            requestObject = $inputs.requestObject
        }
    }
    catch {
        throw $_
    }
    finally {
        Disconnect-VIServer `
            -Server $vCenter `
            -Confirm:$false | Out-Null
    }
}
